import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { twilioChannel } from "eve/channels/twilio";

// Credentials come from env: TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN.
// TWILIO_FROM_NUMBER is the outbound sender. TWILIO_ALLOW_FROM gates who
// can text the agent ("*" only for local demos). See SETUP.md.
const allowFrom = process.env.TWILIO_ALLOW_FROM ?? "*";

export default twilioChannel({
  allowFrom:
    allowFrom === "*" ? "*" : allowFrom.split(",").map((n) => n.trim()),
  messaging: {
    from: process.env.TWILIO_FROM_NUMBER!,
  },
});

import { randomUUID } from "node:crypto";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type Reminder = {
  id: string;
  phoneNumber: string;
  text: string;
  runAt: string;
  status: "pending" | "claimed" | "done";
  leaseUntil: string | null;
};

const STORE_PATH = path.join(process.cwd(), "var", "reminders.json");

async function load(): Promise<Reminder[]> {
  try {
    return JSON.parse(await readFile(STORE_PATH, "utf-8")) as Reminder[];
  } catch {
    return [];
  }
}

async function save(reminders: Reminder[]): Promise<void> {
  await mkdir(path.dirname(STORE_PATH), { recursive: true });
  await writeFile(
    STORE_PATH,
    `${JSON.stringify(reminders, null, 2)}\n`,
    "utf-8"
  );
}

export async function createReminder(input: {
  phoneNumber: string;
  text: string;
  runAt: Date;
}): Promise<Reminder> {
  const reminders = await load();
  const reminder: Reminder = {
    id: randomUUID(),
    phoneNumber: input.phoneNumber,
    text: input.text,
    runAt: input.runAt.toISOString(),
    status: "pending",
    leaseUntil: null,
  };
  reminders.push(reminder);
  await save(reminders);
  return reminder;
}

/** Atomically claim due reminders so overlapping minute ticks do not double-send. */
export async function claimDue(options: {
  now: Date;
  limit: number;
  leaseForMs: number;
}): Promise<Reminder[]> {
  const reminders = await load();
  const nowMs = options.now.getTime();
  const leaseUntil = new Date(nowMs + options.leaseForMs).toISOString();
  const claimed: Reminder[] = [];

  for (const reminder of reminders) {
    if (claimed.length >= options.limit) break;
    if (reminder.status === "done") continue;
    if (new Date(reminder.runAt).getTime() > nowMs) continue;
    if (
      reminder.status === "claimed" &&
      reminder.leaseUntil &&
      new Date(reminder.leaseUntil).getTime() > nowMs
    ) {
      continue;
    }
    reminder.status = "claimed";
    reminder.leaseUntil = leaseUntil;
    claimed.push(reminder);
  }

  if (claimed.length > 0) await save(reminders);
  return claimed;
}

export async function completeReminder(id: string): Promise<void> {
  const reminders = await load();
  const reminder = reminders.find((r) => r.id === id);
  if (!reminder) return;
  reminder.status = "done";
  reminder.leaseUntil = null;
  await save(reminders);
}

export async function releaseReminder(
  id: string,
  retryAt: Date
): Promise<void> {
  const reminders = await load();
  const reminder = reminders.find((r) => r.id === id);
  if (!reminder) return;
  reminder.status = "pending";
  reminder.leaseUntil = null;
  reminder.runAt = retryAt.toISOString();
  await save(reminders);
}

import { defineSchedule } from "eve/schedules";

import twilio from "../channels/twilio";
import {
  claimDue,
  completeReminder,
  releaseReminder,
} from "../lib/reminder-store";

// One-minute dispatcher for application-managed reminders.
// Demos: dynamic scheduling (CRUD row + cron claim + receive).
export default defineSchedule({
  cron: "* * * * *",
  run({ receive, waitUntil, appAuth }) {
    waitUntil(
      (async () => {
        const jobs = await claimDue({
          now: new Date(),
          limit: 25,
          leaseForMs: 5 * 60_000,
        });

        await Promise.all(
          jobs.map(async (job) => {
            try {
              await receive(twilio, {
                message: [
                  "DELIVER_REMINDER",
                  `Reminder id: ${job.id}`,
                  `Text: ${job.text}`,
                ].join("\n"),
                target: { phoneNumber: job.phoneNumber },
                auth: appAuth,
              });
              await completeReminder(job.id);
            } catch (error) {
              console.error("sms-reminder: deliver failed", job.id, error);
              await releaseReminder(job.id, new Date(Date.now() + 60_000));
            }
          })
        );
      })()
    );
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { createReminder } from "../lib/reminder-store";

export default defineTool({
  description:
    "Schedule a one-time SMS reminder. Convert local time to ISO 8601 with an explicit offset before calling. On SMS, the recipient is the texter; elsewhere, pass phoneNumber in E.164.",
  inputSchema: z.object({
    text: z.string().min(1).max(1000),
    runAt: z
      .string()
      .datetime({ offset: true })
      .describe("When to send the reminder, ISO 8601 with offset"),
    phoneNumber: z
      .string()
      .regex(/^\+[1-9]\d{6,14}$/)
      .optional()
      .describe("E.164 phone; required when not called from an inbound SMS"),
  }),
  async execute({ text, runAt, phoneNumber }, ctx) {
    const auth = ctx.session.auth.current;
    const fromSms =
      auth?.principalType === "user" && auth.authenticator === "twilio"
        ? auth.principalId
        : null;
    const recipient = fromSms ?? phoneNumber ?? null;
    if (!recipient) {
      throw new Error(
        "phoneNumber is required when the session is not an inbound SMS."
      );
    }

    const when = new Date(runAt);
    if (Number.isNaN(when.getTime()) || when.getTime() <= Date.now()) {
      throw new Error(
        "runAt must be a future timestamp with a timezone offset."
      );
    }

    const reminder = await createReminder({
      phoneNumber: recipient,
      text,
      runAt: when,
    });

    return {
      id: reminder.id,
      runAt: reminder.runAt,
      text: reminder.text,
      phoneNumber: reminder.phoneNumber,
    };
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Schedules a one-time reminder via create_reminder.",
  async test(t) {
    await t.send(
      [
        "Schedule a reminder for +15551234567 at 2099-01-15T09:00:00Z",
        'with the text "Call the plumber".',
        "Call create_reminder now — do not ask clarifying questions.",
      ].join(" ")
    );
    t.succeeded();
    t.calledTool("create_reminder", {
      input: {
        text: /plumber/i,
        phoneNumber: "+15551234567",
      },
    });
  },
});

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";

export default defineEval({
  description: "DELIVER_REMINDER turns reply with only the reminder text.",
  async test(t) {
    await t.send(
      ["DELIVER_REMINDER", "Reminder id: demo", "Text: Call the plumber"].join(
        "\n"
      )
    );
    t.succeeded();
    t.check(t.reply, includes(/Call the plumber/i));
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
});
